  # Long Exit Normal
  # ---------------------------------------------------------------------------------------------
  def long_exit_normal(
    self,
    pair: str,
    current_rate: float,
    profit_stake: float,
    profit_ratio: float,
    profit_current_stake_ratio: float,
    profit_init_ratio: float,
    max_profit: float,
    max_loss: float,
    filled_orders,
    filled_entries,
    filled_exits,
    last_candle,
    previous_candle_1,
    previous_candle_2,
    previous_candle_3,
    previous_candle_4,
    previous_candle_5,
    trade: "Trade",
    current_time: "datetime",
    enter_tags,
  ) -> tuple:
    mark_profit_target = self.mark_profit_target
    set_profit_target = self._set_profit_target
    exit_profit_target = self.exit_profit_target

    mode_name = self.long_normal_mode_name

    sell = False

    # if the profit is negative skip checking these
    if profit_init_ratio > 0.0:
      # Original sell signals
      sell, signal_name = self.long_exit_signals(
        mode_name,
        profit_init_ratio,
        max_profit,
        max_loss,
        last_candle,
        previous_candle_1,
        previous_candle_2,
        previous_candle_3,
        previous_candle_4,
        previous_candle_5,
        trade,
        current_time,
        enter_tags,
      )

      # Main sell signals
      if not sell:
        sell, signal_name = self.long_exit_main(
          mode_name,
          profit_init_ratio,
          max_profit,
          max_loss,
          last_candle,
          previous_candle_1,
          previous_candle_2,
          previous_candle_3,
          previous_candle_4,
          previous_candle_5,
          trade,
          current_time,
          enter_tags,
        )

      # Williams %R based sells
      if not sell:
        sell, signal_name = self.long_exit_williams_r(
          mode_name,
          profit_init_ratio,
          max_profit,
          max_loss,
          last_candle,
          previous_candle_1,
          previous_candle_2,
          previous_candle_3,
          previous_candle_4,
          previous_candle_5,
          trade,
          current_time,
          enter_tags,
        )

      # Downtrend/descending based sells
      if not sell:
        sell, signal_name = self.long_exit_dec(
          mode_name,
          profit_init_ratio,
          max_profit,
          max_loss,
          last_candle,
          previous_candle_1,
          previous_candle_2,
          previous_candle_3,
          previous_candle_4,
          previous_candle_5,
          trade,
          current_time,
          enter_tags,
        )

    # Stoplosses
    if not sell:
      sell, signal_name = self.long_exit_stoploss(
        mode_name,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        max_profit,
        max_loss,
        filled_orders,
        filled_entries,
        filled_exits,
        last_candle,
        previous_candle_1,
        previous_candle_2,
        previous_candle_3,
        previous_candle_4,
        previous_candle_5,
        trade,
        current_time,
        enter_tags,
      )

    cache = self.target_profit_cache
    cache_data = cache.data if cache is not None else None
    profit_target_get = cache_data.get if cache_data is not None else None

    # Profit Target Signal
    # Check if pair exist on target_profit_cache
    target_data = profit_target_get(pair) if profit_target_get is not None else None
    if target_data is not None:
      previous_rate = target_data["rate"]
      previous_profit = target_data["profit"]
      previous_sell_reason = target_data["sell_reason"]
      previous_time_profit_reached = datetime.fromisoformat(target_data["time_profit_reached"])

      sell_max, signal_name_max = exit_profit_target(
        mode_name,
        pair,
        trade,
        current_time,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        last_candle,
        previous_candle_1,
        previous_rate,
        previous_profit,
        previous_sell_reason,
        previous_time_profit_reached,
        enter_tags,
      )
      if sell_max and signal_name_max is not None:
        return True, f"{signal_name_max}_m"
      if previous_sell_reason == f"exit_{mode_name}_stoploss_u_e":
        if profit_ratio > (previous_profit + 0.005):
          mark_pair, mark_signal = mark_profit_target(
            mode_name,
            pair,
            True,
            previous_sell_reason,
            trade,
            current_time,
            current_rate,
            profit_ratio,
            last_candle,
            previous_candle_1,
          )
          if mark_pair:
            set_profit_target(pair, mark_signal, current_rate, profit_ratio, current_time)
      elif (profit_init_ratio > (previous_profit + 0.001)) and (
        previous_sell_reason != f"exit_{mode_name}_stoploss_doom"
      ):
        # Update the target, raise it.
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          True,
          previous_sell_reason,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )
        if mark_pair:
          set_profit_target(pair, mark_signal, current_rate, profit_init_ratio, current_time)

    # Add the pair to the list, if a sell triggered and conditions met
    if sell and signal_name is not None:
      previous_profit = None
      previous_sell_reason = ""
      target_data = profit_target_get(pair) if profit_target_get is not None else None
      if target_data is not None:
        previous_profit = target_data["profit"]
        previous_sell_reason = target_data["sell_reason"]
      if signal_name in [
        f"exit_{mode_name}_stoploss_doom",
        f"exit_{mode_name}_stoploss_u_e",
      ] and (
        previous_sell_reason
        not in [
          f"exit_{mode_name}_stoploss_doom",
          f"exit_profit_{mode_name}_stoploss_u_e",
        ]
      ):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_ratio,
          last_candle,
          previous_candle_1,
        )
        if mark_pair:
          set_profit_target(pair, mark_signal, current_rate, profit_ratio, current_time)
        else:
          # Just sell it, without maximize
          return True, f"{signal_name}"
      elif (previous_profit is None) or (previous_profit < profit_init_ratio):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )
        if mark_pair:
          set_profit_target(pair, mark_signal, current_rate, profit_init_ratio, current_time)
        else:
          # Just sell it, without maximize
          return True, f"{signal_name}"
    else:
      if profit_init_ratio >= 0.005:
        previous_profit = None
        target_data = profit_target_get(pair) if profit_target_get is not None else None
        if target_data is not None:
          previous_profit = target_data["profit"]
        if (previous_profit is None) or (previous_profit < profit_init_ratio):
          mark_signal = f"exit_profit_{mode_name}_max"
          set_profit_target(pair, mark_signal, current_rate, profit_init_ratio, current_time)

    if signal_name not in [
      f"exit_profit_{mode_name}_max",
      f"exit_{mode_name}_stoploss_doom",
      f"exit_{mode_name}_stoploss_u_e",
    ]:
      if sell and (signal_name is not None):
        return True, f"{signal_name}"

    #  Here ends exit signal conditions for long_exit_normal

    return False, None

  # Long Exit Pump
  # ---------------------------------------------------------------------------------------------
  def long_exit_pump(
    self,
    pair: str,
    current_rate: float,
    profit_stake: float,
    profit_ratio: float,
    profit_current_stake_ratio: float,
    profit_init_ratio: float,
    max_profit: float,
    max_loss: float,
    filled_orders,
    filled_entries,
    filled_exits,
    last_candle,
    previous_candle_1,
    previous_candle_2,
    previous_candle_3,
    previous_candle_4,
    previous_candle_5,
    trade: "Trade",
    current_time: "datetime",
    enter_tags,
  ) -> tuple:
    mark_profit_target = self.mark_profit_target
    set_profit_target = self._set_profit_target
    exit_profit_target = self.exit_profit_target

    mode_name = self.long_pump_mode_name

    sell = False
    signal_name = None

    stoploss_doom = f"exit_{mode_name}_stoploss_doom"
    stoploss_ue = f"exit_{mode_name}_stoploss_u_e"
    max_signal = f"exit_profit_{mode_name}_max"

    candle_args = (
      last_candle,
      previous_candle_1,
      previous_candle_2,
      previous_candle_3,
      previous_candle_4,
      previous_candle_5,
    )

    common_args = (
      mode_name,
      profit_init_ratio,
      max_profit,
      max_loss,
      *candle_args,
      trade,
      current_time,
      enter_tags,
    )

    # Profit-based exits
    if profit_init_ratio > 0.0:
      exit_checks = (
        self.long_exit_signals,
        self.long_exit_main,
        self.long_exit_williams_r,
        self.long_exit_dec,
      )

      for exit_check in exit_checks:
        sell, signal_name = exit_check(*common_args)

        if sell:
          break

    # Stoploss exits
    if not sell:
      sell, signal_name = self.long_exit_stoploss(
        mode_name,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        max_profit,
        max_loss,
        filled_orders,
        filled_entries,
        filled_exits,
        *candle_args,
        trade,
        current_time,
        enter_tags,
      )

    # Cached target profit data
    cache = self.target_profit_cache
    cache_data = cache.data if cache is not None else None
    profit_target_get = cache_data.get if cache_data is not None else None
    target_data = profit_target_get(pair) if profit_target_get is not None else None
    previous_profit = target_data["profit"] if target_data else None
    previous_sell_reason = target_data["sell_reason"] if target_data else ""

    # Profit target logic
    if target_data:
      previous_rate = target_data["rate"]

      previous_time_profit_reached = datetime.fromisoformat(target_data["time_profit_reached"])

      sell_max, signal_name_max = exit_profit_target(
        mode_name,
        pair,
        trade,
        current_time,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        last_candle,
        previous_candle_1,
        previous_rate,
        previous_profit,
        previous_sell_reason,
        previous_time_profit_reached,
        enter_tags,
      )

      if sell_max and signal_name_max is not None:
        return True, f"{signal_name_max}_m"

      if previous_sell_reason == stoploss_ue:
        if profit_ratio > (previous_profit + 0.005):
          mark_pair, mark_signal = mark_profit_target(
            mode_name,
            pair,
            True,
            previous_sell_reason,
            trade,
            current_time,
            current_rate,
            profit_ratio,
            last_candle,
            previous_candle_1,
          )

          if mark_pair:
            set_profit_target(
              pair,
              mark_signal,
              current_rate,
              profit_ratio,
              current_time,
            )

      elif profit_init_ratio > (previous_profit + 0.001) and previous_sell_reason != stoploss_doom:
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          True,
          previous_sell_reason,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_init_ratio,
            current_time,
          )

    # Sell triggered
    if sell and signal_name is not None:
      if signal_name in (stoploss_doom, stoploss_ue):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_ratio,
            current_time,
          )

        else:
          return True, signal_name

      elif previous_profit is None or previous_profit < profit_init_ratio:
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_init_ratio,
            current_time,
          )

        else:
          return True, signal_name

    # Update cached max profit
    elif profit_init_ratio >= 0.005:
      if previous_profit is None or previous_profit < profit_init_ratio:
        set_profit_target(
          pair,
          max_signal,
          current_rate,
          profit_init_ratio,
          current_time,
        )

    # Final sell validation
    if sell and signal_name is not None and signal_name not in (max_signal, stoploss_doom, stoploss_ue):
      return True, signal_name

    return False, None

  # Long Exit Quick
  # ---------------------------------------------------------------------------------------------
  def long_exit_quick(
    self,
    pair: str,
    current_rate: float,
    profit_stake: float,
    profit_ratio: float,
    profit_current_stake_ratio: float,
    profit_init_ratio: float,
    max_profit: float,
    max_loss: float,
    filled_orders,
    filled_entries,
    filled_exits,
    last_candle,
    previous_candle_1,
    previous_candle_2,
    previous_candle_3,
    previous_candle_4,
    previous_candle_5,
    trade: "Trade",
    current_time: "datetime",
    enter_tags,
  ) -> tuple:
    mark_profit_target = self.mark_profit_target
    set_profit_target = self._set_profit_target
    exit_profit_target = self.exit_profit_target

    mode_name = self.long_quick_mode_name

    sell = False
    signal_name = None

    stoploss_doom = f"exit_{mode_name}_stoploss_doom"
    stoploss_ue = f"exit_{mode_name}_stoploss_u_e"
    profit_max_signal = f"exit_profit_{mode_name}_max"

    candle_args = (
      last_candle,
      previous_candle_1,
      previous_candle_2,
      previous_candle_3,
      previous_candle_4,
      previous_candle_5,
    )

    common_args = (
      mode_name,
      profit_init_ratio,
      max_profit,
      max_loss,
      *candle_args,
      trade,
      current_time,
      enter_tags,
    )

    # -------------------------------------------------------------------------
    # Profit-based exit signals
    # -------------------------------------------------------------------------
    if profit_init_ratio > 0.0:
      exit_checks = (
        self.long_exit_signals,
        self.long_exit_main,
        self.long_exit_williams_r,
        self.long_exit_dec,
      )

      for exit_check in exit_checks:
        sell, signal_name = exit_check(*common_args)

        if sell:
          break

    # -------------------------------------------------------------------------
    # Stoploss
    # -------------------------------------------------------------------------
    if not sell:
      sell, signal_name = self.long_exit_stoploss(
        mode_name,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        max_profit,
        max_loss,
        filled_orders,
        filled_entries,
        filled_exits,
        *candle_args,
        trade,
        current_time,
        enter_tags,
      )

    # -------------------------------------------------------------------------
    # Extra quick exit logic
    # -------------------------------------------------------------------------
    if not sell and 0.02 < profit_init_ratio <= 0.09:
      rsi_14 = last_candle["RSI_14"]
      mfi_14 = last_candle["MFI_14"]
      willr_14 = last_candle["WILLR_14"]
      rsi_3 = last_candle["RSI_3"]
      rsi_3_15m = last_candle["RSI_3_15m"]

      quick_conditions = (
        (rsi_14 > 78.0, "q_1"),
        (mfi_14 > 84.0, "q_2"),
        (willr_14 >= -0.1, "q_3"),
        (
          rsi_14 >= 72.0 and rsi_3 > 90.0 and rsi_3_15m > 90.0,
          "q_4",
        ),
        (rsi_3_15m > 96.0, "q_5"),
        (rsi_3 > 85.0 and rsi_3_15m > 85.0, "q_6"),
        (rsi_3 > 90.0 and rsi_3_15m > 80.0, "q_7"),
        (rsi_3 > 92.0 and rsi_3_15m > 75.0, "q_8"),
        (rsi_3 > 94.0 and rsi_3_15m > 70.0, "q_9"),
        (rsi_3 > 99.0, "q_10"),
      )

      for condition, suffix in quick_conditions:
        if condition:
          sell = True
          signal_name = f"exit_{mode_name}_{suffix}"
          break

    # -------------------------------------------------------------------------
    # Cached target data
    # -------------------------------------------------------------------------
    cache = self.target_profit_cache
    cache_data = cache.data if cache is not None else None
    profit_target_get = cache_data.get if cache_data is not None else None
    target_data = profit_target_get(pair) if profit_target_get is not None else None
    previous_profit = target_data["profit"] if target_data else None
    previous_sell_reason = target_data["sell_reason"] if target_data else ""

    # -------------------------------------------------------------------------
    # Profit target logic
    # -------------------------------------------------------------------------
    if target_data:
      previous_rate = target_data["rate"]

      previous_time_profit_reached = datetime.fromisoformat(target_data["time_profit_reached"])

      sell_max, signal_name_max = exit_profit_target(
        mode_name,
        pair,
        trade,
        current_time,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        last_candle,
        previous_candle_1,
        previous_rate,
        previous_profit,
        previous_sell_reason,
        previous_time_profit_reached,
        enter_tags,
      )

      if sell_max and signal_name_max is not None:
        return True, f"{signal_name_max}_m"

      if previous_sell_reason == stoploss_ue:
        if profit_ratio > (previous_profit + 0.001):
          mark_pair, mark_signal = mark_profit_target(
            mode_name,
            pair,
            True,
            previous_sell_reason,
            trade,
            current_time,
            current_rate,
            profit_ratio,
            last_candle,
            previous_candle_1,
          )

          if mark_pair:
            set_profit_target(
              pair,
              mark_signal,
              current_rate,
              profit_ratio,
              current_time,
            )

      elif profit_init_ratio > (previous_profit + 0.001) and previous_sell_reason != stoploss_doom:
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          True,
          previous_sell_reason,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_init_ratio,
            current_time,
          )

    # -------------------------------------------------------------------------
    # Sell triggered logic
    # -------------------------------------------------------------------------
    if sell and signal_name is not None:
      if signal_name in (stoploss_doom, stoploss_ue) and previous_sell_reason not in (
        stoploss_doom,
        f"exit_profit_{mode_name}_stoploss_u_e",
      ):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_ratio,
            current_time,
          )

        else:
          return True, signal_name

      elif previous_profit is None or previous_profit < profit_init_ratio:
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_init_ratio,
            current_time,
          )

        else:
          return True, signal_name

    # -------------------------------------------------------------------------
    # Update max cached profit
    # -------------------------------------------------------------------------
    elif profit_init_ratio >= 0.005:
      if previous_profit is None or previous_profit < profit_init_ratio:
        set_profit_target(
          pair,
          profit_max_signal,
          current_rate,
          profit_init_ratio,
          current_time,
        )

    # -------------------------------------------------------------------------
    # Final sell validation
    # -------------------------------------------------------------------------
    if (
      sell
      and signal_name is not None
      and signal_name
      not in (
        profit_max_signal,
        stoploss_doom,
        stoploss_ue,
      )
    ):
      return True, signal_name

    return False, None

  # Long Exit Rebuy
  # ---------------------------------------------------------------------------------------------
  def long_exit_rebuy(
    self,
    pair: str,
    current_rate: float,
    profit_stake: float,
    profit_ratio: float,
    profit_current_stake_ratio: float,
    profit_init_ratio: float,
    max_profit: float,
    max_loss: float,
    filled_entries,
    filled_exits,
    last_candle,
    previous_candle_1,
    previous_candle_2,
    previous_candle_3,
    previous_candle_4,
    previous_candle_5,
    trade: "Trade",
    current_time: "datetime",
    enter_tags,
  ) -> tuple:
    is_futures_mode = self.is_futures_mode

    mark_profit_target = self.mark_profit_target
    set_profit_target = self._set_profit_target
    exit_profit_target = self.exit_profit_target

    mode_name = self.long_rebuy_mode_name
    stoploss_doom = f"exit_{mode_name}_stoploss_doom"
    stoploss_u_e = f"exit_{mode_name}_stoploss_u_e"
    profit_max = f"exit_profit_{mode_name}_max"

    sell = False
    signal_name = None

    signal_args = (
      mode_name,
      profit_current_stake_ratio,
      max_profit,
      max_loss,
      last_candle,
      previous_candle_1,
      previous_candle_2,
      previous_candle_3,
      previous_candle_4,
      previous_candle_5,
      trade,
      current_time,
      enter_tags,
    )

    # Original sell signals
    for exit_func in (
      self.long_exit_signals,
      self.long_exit_main,
      self.long_exit_williams_r,
      self.long_exit_dec,
    ):
      sell, signal_name = exit_func(*signal_args)

      if sell:
        break

    # Stoplosses
    if not sell:
      leverage = trade.leverage
      entry_cost = filled_entries[0].safe_filled * filled_entries[0].safe_price

      is_system_v3, is_system_v3_1, is_system_v3_2 = self.get_system_version_flags(trade)

      if is_system_v3_2:
        threshold = (
          self.system_v3_2_stop_threshold_futures_rebuy
          if is_futures_mode
          else self.system_v3_2_stop_threshold_spot_rebuy
        )

        if self.system_v3_2_stops_enable and profit_stake < -(entry_cost * threshold / leverage):
          sell, signal_name = True, stoploss_doom

      elif is_system_v3_1:
        threshold = (
          self.system_v3_1_stop_threshold_futures_rebuy
          if is_futures_mode
          else self.system_v3_1_stop_threshold_spot_rebuy
        )

        if profit_stake < -(entry_cost * threshold / leverage):
          sell, signal_name = True, stoploss_doom

      elif is_system_v3:
        threshold = (
          self.system_v3_stop_threshold_futures_rebuy if is_futures_mode else self.system_v3_stop_threshold_spot_rebuy
        )

        if profit_stake < -(entry_cost * threshold / leverage):
          sell, signal_name = True, stoploss_doom

      else:
        threshold = self.stop_threshold_futures_rebuy if is_futures_mode else self.stop_threshold_spot_rebuy

        if profit_stake < -(entry_cost * threshold / leverage) and (
          trade.open_date_utc.replace(tzinfo=None) >= datetime(2024, 9, 13) or self.is_backtest_mode()
        ):
          sell, signal_name = True, stoploss_doom

    # Profit Target Signal
    cache = self.target_profit_cache
    cache_data = cache.data if cache is not None else None
    profit_target_get = cache_data.get if cache_data is not None else None
    target_data = profit_target_get(pair) if profit_target_get is not None else None
    previous_profit = target_data["profit"] if target_data else None
    previous_sell_reason = target_data["sell_reason"] if target_data else ""

    if target_data:
      previous_rate = target_data["rate"]
      previous_time_profit_reached = datetime.fromisoformat(target_data["time_profit_reached"])

      sell_max, signal_name_max = exit_profit_target(
        mode_name,
        pair,
        trade,
        current_time,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        last_candle,
        previous_candle_1,
        previous_rate,
        previous_profit,
        previous_sell_reason,
        previous_time_profit_reached,
        enter_tags,
      )

      if sell_max and signal_name_max is not None:
        return True, f"{signal_name_max}_m"

      if previous_sell_reason == stoploss_u_e:
        if profit_ratio > (previous_profit + 0.001):
          mark_pair, mark_signal = mark_profit_target(
            mode_name,
            pair,
            True,
            previous_sell_reason,
            trade,
            current_time,
            current_rate,
            profit_ratio,
            last_candle,
            previous_candle_1,
          )

          if mark_pair:
            set_profit_target(
              pair,
              mark_signal,
              current_rate,
              profit_ratio,
              current_time,
            )

      elif profit_init_ratio > (previous_profit + 0.001) and previous_sell_reason != stoploss_doom:
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          True,
          previous_sell_reason,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_init_ratio,
            current_time,
          )

    # Add the pair to the list, if a sell triggered and conditions met
    if sell and signal_name is not None:
      if signal_name in (stoploss_doom, stoploss_u_e):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_ratio,
            current_time,
          )
        else:
          return True, signal_name

      elif (previous_profit is None) or (previous_profit < profit_init_ratio):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )

        if mark_pair:
          set_profit_target(
            pair,
            mark_signal,
            current_rate,
            profit_init_ratio,
            current_time,
          )
        else:
          return True, signal_name

    else:
      if profit_init_ratio >= 0.005:
        if (previous_profit is None) or (previous_profit < profit_init_ratio):
          set_profit_target(
            pair,
            profit_max,
            current_rate,
            profit_init_ratio,
            current_time,
          )

    if signal_name not in (
      profit_max,
      stoploss_doom,
      stoploss_u_e,
    ):
      if sell and signal_name is not None:
        return True, signal_name

    # Here ends exit signal conditions for long_exit_rebuy
    return False, None

