    if has_order_tags and (not partial_sell) and (grind_5_sub_grind_count < grind_5_max_sub_grinds):
      if (
        (
          ((grind_5_sub_grind_count > 0) and grind_5_distance_ratio < grind_5_sub_thresholds[grind_5_sub_grind_count])
          or ((is_derisk or is_derisk_calc) and grind_5_sub_grind_count == 0)
          or (is_grind_mode and grind_5_sub_grind_count == 0)
        )
        and (grind_entry_retry_time > last_filled_entry.order_filled_utc)
        and ((grind_force_order_age_time > last_filled_order.order_filled_utc) or slice_profit_lt_neg_0_06)
        and (
          num_open_grinds_eq_0
          or (grind_order_age_time > last_filled_order.order_filled_utc)
          or slice_profit_lt_neg_0_06
        )
        # and ((num_open_grinds == 0) or (slice_profit < -0.03))
        and is_long_grind_entry
        and is_not_trade_max_stake
      ):
        buy_amount = slice_amount * grind_5_stakes[grind_5_sub_grind_count] / stake_scale_leverage
        if buy_amount < (min_stake * 1.5):
          buy_amount = min_stake * 1.5
        if buy_amount > max_stake:
          return None
        grind_profit = 0.0
        grind_profit_stake = 0.0
        if grind_5_sub_grind_count > 0:
          grind_profit = (exit_rate - grind_5_current_open_rate) / grind_5_current_open_rate
          grind_profit_stake = grind_5_current_grind_stake_profit
        send_msg(
          notification_msg(
            "grinding-entry",
            tag="gd5",
            pair=trade_pair,
            rate=current_rate,
            stake_amount=buy_amount,
            profit_stake=profit_stake,
            profit_ratio=profit_ratio,
            stake_currency=stake_currency,
            grind_profit_stake=grind_5_current_grind_stake_profit,
            grind_profit_pct=grind_profit,
          )
        )
        log.info(
          f"Grinding entry (gd5) [{current_time}] [{trade_pair}] | Rate: {current_rate} | Stake amount: {buy_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}% | Grind profit: {(grind_profit * 100.0):.2f}% ({grind_5_current_grind_stake_profit} {stake_currency})"
        )
        order_tag = "gd5"
        if has_order_tags:
          return buy_amount, order_tag
        else:
          return buy_amount

    # Sell
    if grind_5_sub_grind_count > 0:
      grind_profit = (exit_rate - grind_5_current_open_rate) / grind_5_current_open_rate
      if grind_profit > (grind_5_profit_threshold + fee_open_rate + fee_close_rate):
        sell_amount = grind_5_total_amount * exit_rate / trade_leverage
        if ((current_stake_amount / trade_leverage) - sell_amount) < (min_stake * 1.55):
          sell_amount = (trade_amount * exit_rate / trade_leverage) - (min_stake * 1.55)
        ft_sell_amount = sell_amount * trade_leverage * (trade_stake_amount / trade_amount) / exit_rate
        if sell_amount > min_stake and ft_sell_amount > min_stake:
          send_msg(
            notification_msg(
              "grinding-exit",
              tag="gd5",
              pair=trade_pair,
              rate=exit_rate,
              stake_amount=sell_amount,
              profit_stake=profit_stake,
              profit_ratio=profit_ratio,
              stake_currency=stake_currency,
              grind_profit_stake=grind_profit * sell_amount * trade_leverage,
              grind_profit_pct=grind_profit,
              coin_amount=grind_5_total_amount,
            )
          )
          log.info(
            f"Grinding exit (gd5) [{current_time}] [{trade_pair}] | Rate: {exit_rate} | Stake amount: {sell_amount} | Coin amount: {grind_5_total_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}% | Grind profit: {(grind_profit * 100.0):.2f}% ({grind_profit * sell_amount * trade_leverage} {stake_currency})"
          )
          order_tag = "gd5"
          for grind_entry_id in grind_5_buy_orders:
            order_tag += " " + str(grind_entry_id)
          if has_order_tags:
            return -ft_sell_amount, order_tag
          else:
            return -ft_sell_amount

    # Grind stop
    if (
      derisk_use_grind_stops
      and (
        (grind_5_sub_grind_count > 0)
        # and (((exit_rate - grind_5_current_open_rate) / grind_5_current_open_rate) < grind_5_stop_grinds)
        and (grind_5_current_grind_stake_profit < (slice_amount * grind_5_stop_grinds))
        and (is_derisk or is_derisk_calc or is_grind_mode)
      )
      # temporary
      and (is_backtest or trade_open_date >= datetime(2026, 6, 18))
    ):
      sell_amount = grind_5_total_amount * exit_rate / trade_leverage
      if ((current_stake_amount / trade_leverage) - sell_amount) < (min_stake * 1.55):
        sell_amount = (trade_amount * exit_rate / trade_leverage) - (min_stake * 1.55)
      ft_sell_amount = sell_amount * trade_leverage * (trade_stake_amount / trade_amount) / exit_rate
      if sell_amount > min_stake and ft_sell_amount > min_stake:
        grind_profit = 0.0
        if grind_5_current_open_rate > 0.0:
          grind_profit = (
            ((exit_rate - grind_5_current_open_rate) / grind_5_current_open_rate)
            if grind_5_is_sell_found
            else profit_ratio
          )
        send_msg(
          notification_msg(
            "grinding-stop",
            tag="dd5",
            pair=trade_pair,
            rate=exit_rate,
            stake_amount=sell_amount,
            profit_stake=profit_stake,
            profit_ratio=profit_ratio,
            stake_currency=stake_currency,
            grind_profit_stake=grind_profit * sell_amount * trade_leverage,
            grind_profit_pct=grind_profit,
            coin_amount=grind_5_total_amount,
          )
        )
        log.info(
          f"Grinding stop exit (dd5) [{current_time}] [{trade_pair}] | Rate: {exit_rate} | Stake amount: {sell_amount} | Coin amount: {grind_5_total_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}% | Grind profit: {(grind_profit * 100.0):.2f}%"
        )
        order_tag = "dd5"
        for grind_entry_id in grind_5_buy_orders:
          order_tag += " " + str(grind_entry_id)
        if has_order_tags:
          return -ft_sell_amount, order_tag
        else:
          return -ft_sell_amount

    # Grinding 6
    # Buy
    if has_order_tags and (not partial_sell) and (grind_6_sub_grind_count < grind_6_max_sub_grinds):
      if (
        (
          ((grind_6_sub_grind_count > 0) and grind_6_distance_ratio < grind_6_sub_thresholds[grind_6_sub_grind_count])
          or ((is_derisk or is_derisk_calc) and grind_6_sub_grind_count == 0)
          or (is_grind_mode and grind_6_sub_grind_count == 0)
        )
        and (grind_entry_retry_time > last_filled_entry.order_filled_utc)
        and ((grind_force_order_age_time > last_filled_order.order_filled_utc) or slice_profit_lt_neg_0_06)
        and (
          num_open_grinds_eq_0
          or (grind_order_age_time > last_filled_order.order_filled_utc)
          or slice_profit_lt_neg_0_06
        )
        # and ((num_open_grinds == 0) or (slice_profit < -0.03))
        and is_long_grind_entry
        and is_not_trade_max_stake
      ):
        buy_amount = slice_amount * grind_6_stakes[grind_6_sub_grind_count] / stake_scale_leverage
        if buy_amount < (min_stake * 1.5):
          buy_amount = min_stake * 1.5
        if buy_amount > max_stake:
          return None
        grind_profit = 0.0
        grind_profit_stake = 0.0
        if grind_6_sub_grind_count > 0:
          grind_profit = (exit_rate - grind_6_current_open_rate) / grind_6_current_open_rate
          grind_profit_stake = grind_6_current_grind_stake_profit
        send_msg(
          notification_msg(
            "grinding-entry",
            tag="gd6",
            pair=trade_pair,
            rate=current_rate,
            stake_amount=buy_amount,
            profit_stake=profit_stake,
            profit_ratio=profit_ratio,
            stake_currency=stake_currency,
            grind_profit_stake=grind_6_current_grind_stake_profit,
            grind_profit_pct=grind_profit,
          )
        )
        log.info(
          f"Grinding entry (gd6) [{current_time}] [{trade_pair}] | Rate: {current_rate} | Stake amount: {buy_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}% | Grind profit: {(grind_profit * 100.0):.2f}% ({grind_6_current_grind_stake_profit} {stake_currency})"
        )
        order_tag = "gd6"
        if has_order_tags:
          return buy_amount, order_tag
        else:
          return buy_amount

    # Sell
    if grind_6_sub_grind_count > 0:
      grind_profit = (exit_rate - grind_6_current_open_rate) / grind_6_current_open_rate
      if grind_profit > (grind_6_profit_threshold + fee_open_rate + fee_close_rate):
        sell_amount = grind_6_total_amount * exit_rate / trade_leverage
        if ((current_stake_amount / trade_leverage) - sell_amount) < (min_stake * 1.55):
          sell_amount = (trade_amount * exit_rate / trade_leverage) - (min_stake * 1.55)
        ft_sell_amount = sell_amount * trade_leverage * (trade_stake_amount / trade_amount) / exit_rate
        if sell_amount > min_stake and ft_sell_amount > min_stake:
          send_msg(
            notification_msg(
              "grinding-exit",
              tag="gd6",
              pair=trade_pair,
              rate=exit_rate,
              stake_amount=sell_amount,
              profit_stake=profit_stake,
              profit_ratio=profit_ratio,
              stake_currency=stake_currency,
              grind_profit_stake=grind_profit * sell_amount * trade_leverage,
              grind_profit_pct=grind_profit,
              coin_amount=grind_6_total_amount,
            )
          )
          log.info(
            f"Grinding exit (gd6) [{current_time}] [{trade_pair}] | Rate: {exit_rate} | Stake amount: {sell_amount} | Coin amount: {grind_6_total_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}% | Grind profit: {(grind_profit * 100.0):.2f}% ({grind_profit * sell_amount * trade_leverage} {stake_currency})"
          )
          order_tag = "gd6"
          for grind_entry_id in grind_6_buy_orders:
            order_tag += " " + str(grind_entry_id)
          if has_order_tags:
            return -ft_sell_amount, order_tag
          else:
            return -ft_sell_amount

    # Grind stop
    if (
      derisk_use_grind_stops
      and (
        (grind_6_sub_grind_count > 0)
        # and (((exit_rate - grind_6_current_open_rate) / grind_6_current_open_rate) < grind_6_stop_grinds)
        and (grind_6_current_grind_stake_profit < (slice_amount * grind_6_stop_grinds))
        and (is_derisk or is_derisk_calc or is_grind_mode)
      )
      # temporary
      and (is_backtest or trade_open_date >= datetime(2026, 6, 18))
    ):
      sell_amount = grind_6_total_amount * exit_rate / trade_leverage
      if ((current_stake_amount / trade_leverage) - sell_amount) < (min_stake * 1.55):
        sell_amount = (trade_amount * exit_rate / trade_leverage) - (min_stake * 1.55)
      ft_sell_amount = sell_amount * trade_leverage * (trade_stake_amount / trade_amount) / exit_rate
      if sell_amount > min_stake and ft_sell_amount > min_stake:
        grind_profit = 0.0
        if grind_6_current_open_rate > 0.0:
          grind_profit = (
            ((exit_rate - grind_6_current_open_rate) / grind_6_current_open_rate)
            if grind_6_is_sell_found
            else profit_ratio
          )
        send_msg(
          notification_msg(
            "grinding-stop",
            tag="dd6",
            pair=trade_pair,
            rate=exit_rate,
            stake_amount=sell_amount,
            profit_stake=profit_stake,
            profit_ratio=profit_ratio,
            stake_currency=stake_currency,
            grind_profit_stake=grind_profit * sell_amount * trade_leverage,
            grind_profit_pct=grind_profit,
            coin_amount=grind_6_total_amount,
          )
        )
        log.info(
          f"Grinding stop exit (dd6) [{current_time}] [{trade_pair}] | Rate: {exit_rate} | Stake amount: {sell_amount} | Coin amount: {grind_6_total_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}% | Grind profit: {(grind_profit * 100.0):.2f}%"
        )
        order_tag = "dd6"
        for grind_entry_id in grind_6_buy_orders:
          order_tag += " " + str(grind_entry_id)
        if has_order_tags:
          return -ft_sell_amount, order_tag
        else:
          return -ft_sell_amount

    # De-risk 1 reentry
    if (
      is_derisk_1
      and not derisk_1_reentry_found
      and derisk_1_order is not None
      and (
        ((current_rate - derisk_1_order.safe_price) / derisk_1_order.safe_price)
        < (self.regular_mode_derisk_1_reentry_futures if is_futures else self.regular_mode_derisk_1_reentry_spot)
      )
    ):
      if (
        (grind_entry_retry_time > last_filled_entry.order_filled_utc)
        and ((grind_force_order_age_time > last_filled_order.order_filled_utc) or slice_profit_lt_neg_0_06)
        and (
          num_open_grinds_eq_0
          or (grind_order_age_time > last_filled_order.order_filled_utc)
          or slice_profit_lt_neg_0_06
        )
        # and ((num_open_grinds == 0) or (slice_profit < -0.03))
        and (
          # (last_candle["protections_long_rebuy"] == True)
          # and (last_candle["protections_long_global"] == True)
          (last_candle["global_protections_long_pump"] == True)
          and (last_candle["global_protections_long_dump"] == True)
        )
        and is_long_grind_entry
      ):
        buy_amount = derisk_1_order.safe_filled * derisk_1_order.safe_price
        if buy_amount < (min_stake * 1.5):
          buy_amount = min_stake * 1.5
        if buy_amount > max_stake:
          return None
        grind_profit = 0.0
        grind_profit_stake = 0.0
        if derisk_1_sub_grind_count > 0:
          grind_profit = (exit_rate - derisk_1_current_open_rate) / derisk_1_current_open_rate
          grind_profit_stake = derisk_1_current_grind_stake_profit
        send_msg(
          notification_msg(
            "re-entry",
            tag="d1",
            pair=trade_pair,
            rate=current_rate,
            stake_amount=buy_amount,
            profit_stake=profit_stake,
            profit_ratio=profit_ratio,
            stake_currency=stake_currency,
            grind_profit_stake=derisk_1_current_grind_stake_profit,
            grind_profit_pct=grind_profit,
          )
        )
        log.info(
          f"Re-entry (d1) [{current_time}] [{trade_pair}] | Rate: {current_rate} | Stake amount: {buy_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}% | Grind profit: {(grind_profit * 100.0):.2f}% ({derisk_1_current_grind_stake_profit} {stake_currency})"
        )
        order_tag = "d1"
        if has_order_tags:
          return buy_amount, order_tag
        else:
          return buy_amount

    # De-risk level 1
    if (
      has_order_tags
      # and not is_derisk_1
      and derisk_1_reentry_found
      and derisk_1_reentry_order is not None
      # and (trade.open_date_utc.replace(tzinfo=None) >= datetime(2024, 4, 5) or is_backtest)
      and derisk_1_distance_ratio
      < (
        (self.regular_mode_derisk_1_reentry_futures if is_futures else self.regular_mode_derisk_1_reentry_spot)
        / stake_scale_leverage
      )
    ):
      sell_amount = derisk_1_reentry_order.safe_filled * exit_rate / trade_leverage
      if ((current_stake_amount / trade_leverage) - sell_amount) < (min_stake * 1.55):
        sell_amount = (trade_amount * exit_rate / trade_leverage) - (min_stake * 1.55)
      ft_sell_amount = sell_amount * trade_leverage * (trade_stake_amount / trade_amount) / exit_rate
      if sell_amount > min_stake and ft_sell_amount > min_stake:
        grind_profit = 0.0
        send_msg(
          notification_msg(
            "de-risk",
            tag="d1",
            pair=trade_pair,
            rate=exit_rate,
            stake_amount=sell_amount,
            profit_stake=profit_stake,
            profit_ratio=profit_ratio,
            stake_currency=stake_currency,
          )
        )
        log.info(
          f"De-risk (d1) [{current_time}] [{trade_pair}] | Rate: {exit_rate} | Stake amount: {sell_amount} | Profit (stake): {profit_stake} | Profit: {(profit_ratio * 100.0):.2f}%"
        )
        return -ft_sell_amount, "d1"

    # # De-risk
    # if (
    #   not is_derisk_found
    #   and (trade.open_date_utc.replace(tzinfo=None) >= datetime(2024, 2, 5) or is_backtest)
    #   and profit_stake
    #   < (
