  # Short Exit Rapid
  # ---------------------------------------------------------------------------------------------
  def short_exit_rapid(
    self,
    pair: str,
    current_rate: float,
    profit_stake: float,
    profit_ratio: float,
    profit_current_stake_ratio: float,
    profit_init_ratio: float,
    max_profit: float,
    max_loss: float,
    filled_entries,
    filled_exits,
    last_candle,
    previous_candle_1,
    previous_candle_2,
    previous_candle_3,
    previous_candle_4,
    previous_candle_5,
    trade: "Trade",
    current_time: "datetime",
    enter_tags,
  ) -> tuple:
    is_futures_mode = self.is_futures_mode
    stops_enable = self.stops_enable
    trade_leverage = trade.leverage

    mark_profit_target = self.mark_profit_target
    set_profit_target = self._set_profit_target
    exit_profit_target = self.exit_profit_target

    mode_name = self.short_rapid_mode_name

    is_backtest = self.is_backtest_mode()
    is_system_v3, is_system_v3_1, is_system_v3_2 = self.get_system_version_flags(trade)
    sell = False
    signal_name = None

    # if the profit is negative skip checking these
    if profit_init_ratio > 0.0:
      # Original sell signals
      sell, signal_name = self.short_exit_signals(
        mode_name,
        profit_init_ratio,
        max_profit,
        max_loss,
        last_candle,
        previous_candle_1,
        previous_candle_2,
        previous_candle_3,
        previous_candle_4,
        previous_candle_5,
        trade,
        current_time,
        enter_tags,
      )

      # Main sell signals
      if not sell:
        sell, signal_name = self.short_exit_main(
          mode_name,
          profit_init_ratio,
          max_profit,
          max_loss,
          last_candle,
          previous_candle_1,
          previous_candle_2,
          previous_candle_3,
          previous_candle_4,
          previous_candle_5,
          trade,
          current_time,
          enter_tags,
        )

      # Williams %R based sells
      if not sell:
        sell, signal_name = self.short_exit_williams_r(
          mode_name,
          profit_init_ratio,
          max_profit,
          max_loss,
          last_candle,
          previous_candle_1,
          previous_candle_2,
          previous_candle_3,
          previous_candle_4,
          previous_candle_5,
          trade,
          current_time,
          enter_tags,
        )

      # Downtrend/descending based sells
      if not sell:
        sell, signal_name = self.short_exit_dec(
          mode_name,
          profit_init_ratio,
          max_profit,
          max_loss,
          last_candle,
          previous_candle_1,
          previous_candle_2,
          previous_candle_3,
          previous_candle_4,
          previous_candle_5,
          trade,
          current_time,
          enter_tags,
        )

    # Extra exit logic
    if not sell:
      last_rsi_14 = last_candle["RSI_14"]
      last_rsi_3 = last_candle["RSI_3"]
      last_rsi_3_15m = last_candle["RSI_3_15m"]
      last_willr_14 = last_candle["WILLR_14"]
      if (0.09 >= profit_init_ratio > 0.005) and (last_rsi_14 < 22.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_1"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_candle["MFI_14"] < 16.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_2"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_willr_14 <= -99.9):
        sell, signal_name = True, f"exit_{mode_name}_rpd_3"
      elif (
        (0.09 >= profit_init_ratio > 0.005)
        and (last_rsi_14 <= 28.0)
        and (last_rsi_3 < 10.0)
        and (last_rsi_3_15m < 10.0)
      ):
        sell, signal_name = True, f"exit_{mode_name}_rpd_4"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_rsi_3_15m < 4.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_5"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_rsi_3 < 15.0) and (last_rsi_3_15m < 15.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_6"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_rsi_3 < 10.0) and (last_rsi_3_15m < 20.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_7"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_rsi_3 < 8.0) and (last_rsi_3_15m < 25.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_8"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_rsi_3 < 6.0) and (last_rsi_3_15m < 30.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_9"
      elif (0.09 >= profit_init_ratio > 0.005) and (last_rsi_3 < 1.0):
        sell, signal_name = True, f"exit_{mode_name}_rpd_10"

      entry_cost = filled_entries[0].safe_filled * filled_entries[0].safe_price
      if is_system_v3_2:
        # Stoplosses
        if self.system_v3_2_stops_enable and (
          profit_stake
          < -(
            entry_cost
            * (
              self.system_v3_2_stop_threshold_rapid_futures
              if is_futures_mode
              else self.system_v3_2_stop_threshold_rapid_spot
            )
            / trade_leverage
          )
        ):
          sell, signal_name = True, f"exit_{mode_name}_stoploss_doom"
      elif is_system_v3_1:
        # Stoplosses
        if stops_enable and (
          profit_stake
          < -(
            entry_cost
            * (
              self.system_v3_1_stop_threshold_rapid_futures
              if is_futures_mode
              else self.system_v3_1_stop_threshold_rapid_spot
            )
            / trade_leverage
          )
        ):
          sell, signal_name = True, f"exit_{mode_name}_stoploss_doom"
      elif is_system_v3:
        # Stoplosses
        if stops_enable and (
          profit_stake
          < -(
            entry_cost
            * (
              self.system_v3_stop_threshold_rapid_futures
              if is_futures_mode
              else self.system_v3_stop_threshold_rapid_spot
            )
            / trade_leverage
          )
        ):
          sell, signal_name = True, f"exit_{mode_name}_stoploss_doom"
      else:
        # Stoplosses
        if (
          (
            stops_enable
            and (
              profit_stake
              < -(
                entry_cost * (self.stop_threshold_rapid_futures if is_futures_mode else self.stop_threshold_rapid_spot)
              )
            )
          )
          # temporary
          and (is_backtest or trade.open_date_utc.replace(tzinfo=None) >= datetime(2024, 9, 13))
        ):
          sell, signal_name = True, f"exit_{mode_name}_stoploss_doom"

    cache = self.target_profit_cache
    cache_data = cache.data if cache is not None else None
    profit_target_get = cache_data.get if cache_data is not None else None

    # Profit Target Signal
    # Check if pair exist on target_profit_cache
    target_data = profit_target_get(pair) if profit_target_get is not None else None
    if target_data is not None:
      previous_rate = target_data["rate"]
      previous_profit = target_data["profit"]
      previous_sell_reason = target_data["sell_reason"]
      previous_time_profit_reached = datetime.fromisoformat(target_data["time_profit_reached"])

      sell_max, signal_name_max = exit_profit_target(
        mode_name,
        pair,
        trade,
        current_time,
        current_rate,
        profit_stake,
        profit_ratio,
        profit_current_stake_ratio,
        profit_init_ratio,
        last_candle,
        previous_candle_1,
        previous_rate,
        previous_profit,
        previous_sell_reason,
        previous_time_profit_reached,
        enter_tags,
      )
      if sell_max and signal_name_max is not None:
        return True, f"{signal_name_max}_m"
      if previous_sell_reason == f"exit_{mode_name}_stoploss_u_e":
        if profit_ratio > (previous_profit + 0.001):
          mark_pair, mark_signal = mark_profit_target(
            mode_name,
            pair,
            True,
            previous_sell_reason,
            trade,
            current_time,
            current_rate,
            profit_ratio,
            last_candle,
            previous_candle_1,
          )
          if mark_pair:
            set_profit_target(pair, mark_signal, current_rate, profit_ratio, current_time)
      elif (profit_init_ratio > (previous_profit + 0.001)) and (
        previous_sell_reason != f"exit_{mode_name}_stoploss_doom"
      ):
        # Update the target, raise it.
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          True,
          previous_sell_reason,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )
        if mark_pair:
          set_profit_target(pair, mark_signal, current_rate, profit_init_ratio, current_time)

    # Add the pair to the list, if a sell triggered and conditions met
    if sell and signal_name is not None:
      previous_profit = None
      previous_sell_reason = ""
      target_data = profit_target_get(pair) if profit_target_get is not None else None
      if target_data is not None:
        previous_profit = target_data["profit"]
        previous_sell_reason = target_data["sell_reason"]
      if signal_name in [
        f"exit_{mode_name}_stoploss_doom",
        f"exit_{mode_name}_stoploss_u_e",
      ] and (
        previous_sell_reason
        not in [
          f"exit_{mode_name}_stoploss_doom",
          f"exit_profit_{mode_name}_stoploss_u_e",
        ]
      ):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_ratio,
          last_candle,
          previous_candle_1,
        )
        if mark_pair:
          set_profit_target(pair, mark_signal, current_rate, profit_ratio, current_time)
        else:
          # Just sell it, without maximize
          return True, f"{signal_name}"
      elif (previous_profit is None) or (previous_profit < profit_init_ratio):
        mark_pair, mark_signal = mark_profit_target(
          mode_name,
          pair,
          sell,
          signal_name,
          trade,
          current_time,
          current_rate,
          profit_init_ratio,
          last_candle,
          previous_candle_1,
        )
        if mark_pair:
          set_profit_target(pair, mark_signal, current_rate, profit_init_ratio, current_time)
        else:
          # Just sell it, without maximize
          return True, f"{signal_name}"
    else:
      if profit_init_ratio >= 0.005:
        previous_profit = None
        target_data = profit_target_get(pair) if profit_target_get is not None else None
        if target_data is not None:
          previous_profit = target_data["profit"]
        if (previous_profit is None) or (previous_profit < profit_init_ratio):
          mark_signal = f"exit_profit_{mode_name}_max"
          set_profit_target(pair, mark_signal, current_rate, profit_init_ratio, current_time)

    if signal_name not in [
      f"exit_profit_{mode_name}_max",
      f"exit_{mode_name}_stoploss_doom",
      f"exit_{mode_name}_stoploss_u_e",
    ]:
      if sell and (signal_name is not None):
        return True, f"{signal_name}"

    #  Here ends exit signal conditions for short_exit_rapid

    return False, None

