    buyback_3_current_open_rate = 0.0
    buyback_3_current_grind_stake = 0.0
    buyback_3_current_grind_stake_profit = 0.0
    buyback_3_is_exit_found = False
    buyback_3_found = False
    buyback_3_buy_orders = []
